parameters.jsCode:
const body = $json.body || $json;
const message = String(body.message || '').trim();
const lower = message.toLowerCase();
const keywords = [
  'ai omic','小o','小O','automation','workflow','rag','n8n','audit','chatbot','pricing','price','cost','fee','quote','quotation','how much','support','aftercare','presales','whatsapp','google sheets','ocr','deepseek',
  '自动化','工作流','流程','价格','报价','费用','收费','多少钱','几多钱','预算','售前','售后','配套','客服','表单','审计','发票','单据','你是谁'
];
const inScope = keywords.some((keyword) => lower.includes(String(keyword).toLowerCase()));
const outOfScopeAnswer = '这个问题可能超出 AI Omic 的范围。小O 只回答关于 AI Omic、工作流自动化、RAG、OCR、服务配套、售前与售后的问题。';
const context = `
AI Omic slogan: Make Work Flow Better. 让工作流更顺。
AI Omic positioning: Malaysia SME workflow automation services.
Service journey: intake form -> free fit check -> paid workflow audit or direct quote -> delivery -> 14-day WhatsApp support -> optional monthly support.
Workflow Audit: RM299-RM499. For unclear needs. Deliverables: simple process map, recommended automation path, budget range, implementation plan.
Basic Automation: RM500-RM1,200. Monthly support RM300-RM500. Good for Excel, Google Sheets, forms, admin tracking, notifications, simple reporting.
AI Automation Flow: RM1,500-RM3,500. Monthly support RM500-RM800. Good for n8n workflows, AI classification, AI replies, document extraction, routing, alerts, approvals.
AI Chatbot: RM2,000-RM4,500. Monthly support RM600-RM1,000. Good for WhatsApp, Web, Telegram, FAQ, document Q&A, lead capture, human handoff.
Quote terms: every quote must state scope, deliverables, exclusions, revision limit, timeline, payment terms, and third-party costs.
Payment default: 50% deposit, 50% before handover.
Included: flow design, build, testing, bug fixing, prompt tuning when applicable, basic training, handover doc, 1 revision, 14-day WhatsApp support.
Not included: n8n Cloud/hosting fees, OpenAI/Claude/DeepSeek API costs, WhatsApp Business API fee, Google Workspace/domains/subscriptions, extra revisions, new features after sign-off.
Monthly support includes: bug fixing, monitoring, small adjustments, light prompt tuning. It excludes new features, new workflows, full account management unless separately arranged.
Account management add-on: RM100/hour or fixed monthly fee by arrangement.
Blog themes: workflow friction, OCR automation, AI operations, reducing manual document handling, OCR -> AI summary/classification -> routing -> archive/review.
Xiao O identity: 小O is AI Omic's website assistant. It should only answer questions about AI Omic and related service topics.
`;
return [{ json: { message, inScope, context, outOfScopeAnswer, page: body.page || '', language: body.language || '', sessionId: body.sessionId || '' } }];

parameters.jsonBody:
={
  "model": "deepseek-chat",
  "temperature": 0.3,
  "messages": [
    {
      "role": "system",
      "content": "You are 小O, the AI Omic website assistant. Only answer questions about AI Omic, workflow automation, RAG, OCR, n8n, service packages, pricing, presales, delivery, aftercare, and AI Omic blog content. If outside scope, politely refuse and redirect to AI Omic-related topics. Use only the provided context. Do not invent pricing, guarantees, platform fees, or technical claims. Answer in the user's language. Keep answers concise, practical, and sales-friendly. Suggest the intake form when the user wants a quote or has a specific workflow."
    },
    {
      "role": "user",
      "content": "Context:\n{{$json.context}}\n\nUser question:\n{{$json.message}}"
    }
  ]
}
